// A Fibonacci iterator that generates numbers lazily
struct Fibonacci {
    a: u64,
    b: u64,
}

impl Fibonacci {
    fn new() -> Self {
        Fibonacci { a: 0, b: 1 }
    }
}

impl Iterator for Fibonacci {
    type Item = u64;

    fn next(&mut self) -> Option<u64> {
        let result = self.a;
        let new_b = self.a.checked_add(self.b)?; // Stop on overflow
        self.a = self.b;
        self.b = new_b;
        Some(result)
    }
}

// A range iterator with a step
struct StepRange {
    current: i64,
    end: i64,
    step: i64,
}

impl StepRange {
    fn new(start: i64, end: i64, step: i64) -> Self {
        StepRange { current: start, end, step }
    }
}

impl Iterator for StepRange {
    type Item = i64;

    fn next(&mut self) -> Option<i64> {
        if (self.step > 0 && self.current >= self.end)
            || (self.step < 0 && self.current <= self.end)
        {
            return None;
        }
        let value = self.current;
        self.current += self.step;
        Some(value)
    }
}

// IntoIterator: make a type work with for loops
struct Playlist {
    songs: Vec<String>,
}

impl IntoIterator for Playlist {
    type Item = String;
    type IntoIter = std::vec::IntoIter<String>;

    fn into_iter(self) -> Self::IntoIter {
        self.songs.into_iter()
    }
}

fn main() {
    // Fibonacci with combinators
    let first_10: Vec<u64> = Fibonacci::new().take(10).collect();
    println!("First 10 Fibonacci: {:?}", first_10);

    let even_fibs: Vec<u64> = Fibonacci::new()
        .filter(|n| n % 2 == 0)
        .take(5)
        .collect();
    println!("First 5 even Fibonacci: {:?}", even_fibs);

    let fib_sum: u64 = Fibonacci::new().take(20).sum();
    println!("Sum of first 20: {}", fib_sum);

    // Step range
    let evens: Vec<i64> = StepRange::new(0, 20, 2).collect();
    println!("Evens: {:?}", evens);

    // Playlist iteration
    let playlist = Playlist {
        songs: vec!["Song A".into(), "Song B".into(), "Song C".into()],
    };
    for song in playlist {
        println!("Playing: {}", song);
    }
}
